import java.util.ArrayList;
import java.util.List;

class Solution {
    private static long gcd(long a, long b) {
        while (b != 0) {
            long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    public static long solve(long[] nums, long p, long[][] queries) {
        int n = nums.length;
        long[] currentNums = new long[n];
        System.arraycopy(nums, 0, currentNums, 0, n);

        long count = 0;

        for (long[] query : queries) {
            int ind = (int) query[0];
            long val = query[1];

            // Update
            currentNums[ind] = val;

            // Check for good subsequence
            List<Long> multiplesOfP = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                if (currentNums[i] % p == 0) {
                    multiplesOfP.add(currentNums[i]);
                }
            }

            boolean existsGoodSubsequence = false;

            if (multiplesOfP.isEmpty()) {
                existsGoodSubsequence = false;
            } else {
                // Calculate GCD of all multiples of p
                long currentGCD = multiplesOfP.get(0);
                for (int i = 1; i < multiplesOfP.size(); i++) {
                    currentGCD = gcd(currentGCD, multiplesOfP.get(i));
                }

                if (currentGCD == p) {
                    // GCD of all multiples of p is p.

                    if (multiplesOfP.size() < n) {
                        // Case 1: There are at least two or more multiples of p, and at least one element 
                        // is not a multiple of p. The set of all multiples of p forms a good subsequence.
                        existsGoodSubsequence = true;
                    } else {
                        // Case 2: All elements are multiples of p, and GCD(nums) = p.
                        // Since n >= 2 (constraint), we can always find a proper subsequence 
                        // whose GCD is p (because GCD(nums/p) = 1).
                        existsGoodSubsequence = true;
                    }
                } else {
                    // GCD of all multiples of p is not p.
                    existsGoodSubsequence = false;
                }
            }

            if (existsGoodSubsequence) {
                count++;
            }
        }

        return count;
    }
}
