import java.util.ArrayList;
import java.util.List;

class Solution {
    private static int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    public static long solve(long[] nums, long p, long[][] queries) {
        int n = nums.length;
        long[] currentNums = new long[n];
        for (int i = 0; i < n; i++) {
            currentNums[i] = nums[i];
        }

        // A good subsequence must have GCD = p and length < n.

        // Check function to determine if a good subsequence exists for the current state of currentNums
        java.util.function.BooleanSupplier check = () -> {
            List<Long> multiplesOfP = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                if (currentNums[i] % p == 0) {
                    multiplesOfP.add(currentNums[i]);
                }
            }

            if (multiplesOfP.isEmpty()) {
                return false;
            }

            long currentGCD = multiplesOfP.get(0);
            for (int i = 1; i < multiplesOfP.size(); i++) {
                currentGCD = gcd((int)currentGCD, (int)multiplesOfP.get(i));
            }

            if (currentGCD != p) {
                return false;
