            if (multiplesOfP.size() < n) {
                // Found a subset whose GCD is p and its length is < n, so it is good.
                return true;
            } else {
                // multiplesOfP.size() == n. All elements are multiples of p, and GCD(nums) = p.
                // Since n >= 2 (from constraints), we can always remove one element to get a proper subsequence.
                // Since GCD(nums/p) = 1, there must exist a proper subsequence whose GCD is p.
                return true;
            }
        };

        long count = 0;
        for (long[] query : queries) {
            int ind = (int) query[0];
            long val = query[1];

            // Update
            currentNums[ind] = val;

            // Check
            if (check.getAsBoolean()) {
                count++;
            }
        }

        return count;
    }
}
